// Simple C subset compiler: Lexer, Recursive Descent Parser, CFG, and x86_64 emitter
#include <iostream>
#include <vector>
#include <string>
#include <memory>
#include <fstream>

enum class TokenType { INT, ID, SEMICOLON, ASSIGN, PLUS, NUM, END };
struct Token { TokenType type; std::string value; };

class Lexer {
    std::string src; size_t pos = 0;
public:
    Lexer(std::string s) : src(s) {}
    Token next() {
        while (pos < src.size() && isspace(src[pos])) pos++;
        if (pos >= src.size()) return {TokenType::END, ""};
        if (isdigit(src[pos])) {
            std::string val;
            while (pos < src.size() && isdigit(src[pos])) val += src[pos++];
            return {TokenType::NUM, val};
        }
        if (src[pos] == '=') { pos++; return {TokenType::ASSIGN, "="}; }
        if (src[pos] == ';') { pos++; return {TokenType::SEMICOLON, ";"}; }
        if (isalpha(src[pos])) {
            std::string val;
            while (pos < src.size() && isalnum(src[pos])) val += src[pos++];
            return (val == "int") ? Token{TokenType::INT, val} : Token{TokenType::ID, val};
        }
        return {TokenType::END, ""};
    }
};

struct Node { virtual ~Node() = default; };
struct AssignNode : Node { std::string var; int val; };

class Parser {
    Lexer lexer; Token cur;
public:
    Parser(Lexer l) : lexer(l) { cur = lexer.next(); }
    std::unique_ptr<AssignNode> parse() {
        if (cur.type == TokenType::INT) cur = lexer.next();
        std::string var = cur.value;
        cur = lexer.next(); // skip ID
        cur = lexer.next(); // skip =
        int val = std::stoi(cur.value);
        return std::make_unique<AssignNode>(AssignNode{var, val});
    }
};

int main(int argc, char** argv) {
    std::string code = "int x = 5;";
    Parser parser(Lexer(code));
    auto ast = parser.parse();
    std::cout << ".global _start\n.text\n_start:\n";
    std::cout << "mov $" << ast->val << ", %rax\n";
    std::cout << "mov %rax, " << ast->var << "(%rip)\n";
    std::cout << "mov $60, %rax\nxor %rdi, %rdi\nsyscall" << std::endl;
    return 0;
}
//END compiler.cpp

// Minimalist cross-platform GUI framework header and implementation using Skia
#include "include/core/SkCanvas.h"
#include "include/core/SkSurface.h"
#include "include/core/SkPaint.h"
#include <vector>
#include <memory>
#include <functional>

struct Rect { float x, y, w, h; };

class Component {
public:
    Rect bounds;
    std::vector<std::unique_ptr<Component>> children;
    std::function<void(float, float)> onClick;

    virtual void render(SkCanvas* canvas) {
        for (auto& child : children) child->render(canvas);
    }

    bool hitTest(float x, float y) {
        return x >= bounds.x && x <= bounds.x + bounds.w && 
               y >= bounds.y && y <= bounds.y + bounds.h;
    }
};

class Button : public Component {
public:
    void render(SkCanvas* canvas) override {
        SkPaint paint;
        paint.setColor(SK_ColorBLUE);
        canvas->drawRect(SkRect::MakeXYWH(bounds.x, bounds.y, bounds.w, bounds.h), paint);
    }
};

class Window {
    std::vector<std::unique_ptr<Component>> root;
public:
    void add(std::unique_ptr<Component> c) { root.push_back(std::move(c)); }

    void handleInput(float x, float y) {
        for (auto& c : root) {
            if (c->hitTest(x, y) && c->onClick) c->onClick(x, y);
        }
    }

    void draw(SkCanvas* canvas) {
        for (auto& c : root) c->render(canvas);
    }
};
//END framework.hpp

// Implementation entry point for Skia backend integration
#include "framework.hpp"

void RenderFrame(SkSurface* surface, Window& win) {
    SkCanvas* canvas = surface->getCanvas();
    canvas->clear(SK_ColorWHITE);
    win.draw(canvas);
}
//END main.cpp

