// Ray tracing engine with BVH acceleration and path tracing support
#include <vector>
#include <memory>
#include <cmath>
#include <algorithm>

struct Vec3 { float x, y, z; };
struct Ray { Vec3 origin, direction; };
struct AABB { Vec3 min, max; };

class BVHNode {
public:
    AABB bounds;
    std::unique_ptr<BVHNode> left, right;
    int objectIndex = -1;
    bool isLeaf() const { return objectIndex != -1; }
};

class RayTracer {
