// High-performance linear algebra library using AVX-512 and template metaprogramming
#include <immintrin.h>
#include <iostream>
#include <vector>
#include <array>

template<size_t Rows, size_t Cols>
struct Matrix {
    alignas(64) float data[Rows * Cols];

    inline float& operator()(size_t r, size_t c) { return data[r * Cols + c]; }
    inline const float& operator()(size_t r, size_t c) const { return data[r * Cols + c]; }
};

template<size_t Rows, size_t Cols, size_t VecSize>
struct VectorOps {
    static void multiply(const Matrix<Rows, Cols>& A, const float* __restrict vec, float* __restrict result) {
        for (size_t i = 0; i < Rows; ++i) {
            __m512 sum = _mm512_setzero_ps();
            for (size_t j = 0; j < Cols; j += 16) {
                __m512 a = _mm512_load_ps(&A.data[i * Cols + j]);
                __m512 v = _mm512_loadu_ps(&vec[j]);
                sum = _mm512_fmadd_ps(a, v, sum);
            }
            result[i] = _mm512_reduce_add_ps(sum);
        }
    }
};

//END linalg.hpp
//main.cpp
int main() {
    constexpr size_t R = 16;
    constexpr size_t C = 16;
    Matrix<R, C> mat;
    float vec[C] __attribute__((aligned(64))) = {1.0f};
    float res[R] = {0.0f};

    for(size_t i = 0; i < R*C; ++i) mat.data[i] = 0.1f;

    VectorOps<R, C, 16>::multiply(mat, vec, res);

    std::cout << "Result[0]: " << res[0] << std::endl;
    return 0;
}
//END main.cpp

// DSP Suite: FIR/IIR Filters, FFT, and VST3 Boilerplate
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>

class FIRFilter {
public:
    FIRFilter(const std::vector<float>& coeffs) : coefficients(coeffs) {}
    float process(float input) {
        buffer.push_back(input);
        if (buffer.size() > coefficients.size()) buffer.erase(buffer.begin());
        float output = 0;
        for (size_t i = 0; i < buffer.size(); ++i)
            output += buffer[buffer.size() - 1 - i] * coefficients[i];
        return output;
    }
private:
    std::vector<float> coefficients;
    std::vector<float> buffer;
};

class FFTProcessor {
public:
    void forward(std::vector<std::complex<float>>& data) {
        size_t n = data.size();
        if (n <= 1) return;
        std::vector<std::complex<float>> even(n/2), odd(n/2);
        for (size_t i = 0; i < n/2; ++i) {
            even[i] = data[i*2];
            odd[i] = data[i*2+1];
        }
        forward(even);
        forward(odd);
        for (size_t k = 0; k < n/2; ++k) {
            std::complex<float> t = std::polar(1.0f, -2 * M_PI * k / n) * odd[k];
            data[k] = even[k] + t;
            data[k + n/2] = even[k] - t;
        }
    }
};
//END DSP_CORE.hpp

