// Distributed search engine with crawler, inverted index, and TF-IDF ranking
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.net.URL;
import java.io.*;

class SearchEngine {
    private final ConcurrentHashMap<String, ConcurrentHashMap<String, Integer>> index = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, Integer> docLengths = new ConcurrentHashMap<>();
    private final AtomicInteger totalDocs = new AtomicInteger(0);

    public void indexDocument(String docId, String content) {
        String[] tokens = content.toLowerCase().split("\\W+");
        docLengths.put(docId, tokens.length);
        for (String token : tokens) {
            index.computeIfAbsent(token, k -> new ConcurrentHashMap<>())
                 .merge(docId, 1, Integer::sum);
        }
        totalDocs.incrementAndGet();
    }

    public Map<String, Double> search(String query) {
        String[] terms = query.toLowerCase().split("\\W+");
        Map<String, Double> scores = new HashMap<>();
        for (String term : terms) {
            if (!index.containsKey(term)) continue;
            double idf = Math.log((double) totalDocs.get() / (1 + index.get(term).size()));
            index.get(term).forEach((docId, tf) -> {
                double score = (double) tf / docLengths.get(docId) * idf;
                scores.merge(docId, score, Double::sum);
            });
        }
        return scores;
    }
}

class Crawler {
    private final SearchEngine engine;
    private final Set<String> visited = ConcurrentHashMap.newKeySet();
    private final ExecutorService executor = Executors.newFixedThreadPool(4);

    public Crawler(SearchEngine engine) { this.engine = engine; }

    public void crawl(String url) {
        executor.submit(() -> {
            if (visited.add(url)) {
                try {
                    Thread.sleep(1000); // Rate limiting
                    String content = fetchContent(url);
                    engine.indexDocument(url, content);
                } catch (Exception e) { }
            }
        });
    }

    private String fetchContent(String url) throws IOException {
        try (Scanner scanner = new Scanner(new URL(url).openStream())) {
            StringBuilder sb = new StringBuilder();
            while (scanner.hasNext()) sb.append(scanner.next()).append(" ");
            return sb.toString();
        }
    }
}

public class Main {
    public static void main(String[] args) {
        SearchEngine engine = new SearchEngine();
        Crawler crawler = new Crawler(engine);
        crawler.crawl("http://example.com");
    }
}

// Java implementation of a PBFT-based blockchain with Merkle verification and ECDSA
import java.security.*;
import java.util.*;
import java.util.stream.Collectors;

class Transaction {
    public String sender;
    public String receiver;
    public double amount;
    public byte[] signature;

    public Transaction(String sender, String receiver, double amount) {
        this.sender = sender;
        this.receiver = receiver;
        this.amount = amount;
    }

    public String getData() {
        return sender + receiver + amount;
    }
}

class Block {
    public int index;
    public long timestamp;
    public List<Transaction> transactions;
    public String previousHash;
    public String merkleRoot;
    public String hash;

    public Block(int index, List<Transaction> transactions, String previousHash) {
        this.index = index;
        this.transactions = transactions;
        this.previousHash = previousHash;
        this.timestamp = System.currentTimeMillis();
        this.merkleRoot = calculateMerkleRoot();
        this.hash = calculateHash();
    }

    public String calculateMerkleRoot() {
        List<String> hashes = transactions.stream().map(t -> t.getData()).collect(Collectors.toList());
        return String.valueOf(hashes.hashCode());
    }

    public String calculateHash() {
        return Integer.toHexString(Objects.hash(index, timestamp, merkleRoot, previousHash));
    }
}

class PBFTNode {
    private int nodeId;
    private List<Block> blockchain = new ArrayList<>();
    private Set<String> preparedMessages = new HashSet<>();

    public PBFTNode(int nodeId) {
        this.nodeId = nodeId;
    }

    public boolean validateBlock(Block block) {
        return block.hash.startsWith("0");
    }

    public void broadcastPrePrepare(Block block) {
        System.out.println("Node " + nodeId + " broadcasting pre-prepare for block " + block.index);
    }
}

public class BlockchainEngine {
    public static void main(String[] args) throws Exception {
        KeyPairGenerator keyGen = KeyPairGenerator.getInstance("EC");
        KeyPair pair = keyGen.generateKeyPair();

        List<Transaction> txs = new ArrayList<>();
        txs.add(new Transaction("Alice", "Bob", 50.0));

        Block genesis = new Block(0, txs, "0");
        PBFTNode node = new PBFTNode(1);

        if(node.validateBlock(genesis)) {
            System.out.println("Block validated via PBFT logic. Hash: " + genesis.hash);
        }
    }
}

// WorkflowEngine.java - A minimal BPMN-inspired workflow engine with JPA persistence and task management
import javax.persistence.*;
import java.util.*;
import java.util.concurrent.*;

@Entity
class WorkflowInstance {
    @Id @GeneratedValue private Long id;
    private String state;
    private String currentTask;
    public Long getId() { return id; }
    public String getState() { return state; }
    public void setState(String state) { this.state = state; }
}

@Entity
class HumanTask {
    @Id @GeneratedValue private Long id;
    private String taskName;
    private boolean completed;
    public void setCompleted(boolean completed) { this.completed = completed; }
}

class WorkflowEngine {
    private final ExecutorService executor = Executors.newFixedThreadPool(4);
    private final EntityManagerFactory emf = Persistence.createEntityManagerFactory("WorkflowPU");

    public void executeTask(Long instanceId, Runnable task) {
        executor.submit(() -> {
            EntityManager em = emf.createEntityManager();
            em.getTransaction().begin();
            try {
                task.run();
                em.getTransaction().commit();
            } catch (Exception e) {
                em.getTransaction().rollback();
            } finally {
                em.close();
            }
        });
    }

    public void completeHumanTask(Long taskId) {
        EntityManager em = emf.createEntityManager();
        em.getTransaction().begin();
        HumanTask task = em.find(HumanTask.class, taskId);
        task.setCompleted(true);
        em.getTransaction().commit();
        em.close();
    }
}

public class Main {
    public static void main(String[] args) {
        WorkflowEngine engine = new WorkflowEngine();
        System.out.println("Workflow Engine Initialized");
    }
}
//END WorkflowEngine.java

// Java static analysis tool for SQLi and XSS detection using AST parsing
import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.MethodCallExpr;
import java.io.File;
import java.util.Arrays;
import java.util.List;

public class SimpleSAST {
    private static final List<String> SQL_SINKS = Arrays.asList("executeQuery", "executeUpdate", "prepareStatement");
    private static final List<String> XSS_SINKS = Arrays.asList("println", "write", "print");

    public static void main(String[] args) throws Exception {
        File projectDir = new File("src/main/java");
        analyzeDirectory(projectDir);
    }

    private static void analyzeDirectory(File dir) throws Exception {
        for (File file : dir.listFiles()) {
            if (file.isDirectory()) analyzeDirectory(file);
            else if (file.getName().endsWith(".java")) {
                CompilationUnit cu = StaticJavaParser.parse(file);
                cu.findAll(MethodDeclaration.class).forEach(method -> {
                    method.findAll(MethodCallExpr.class).forEach(call -> {
                        checkVulnerabilities(call, method);
                    });
                });
            }
        }
    }

    private static void checkVulnerabilities(MethodCallExpr call, MethodDeclaration method) {
        String methodName = call.getNameAsString();

        if (SQL_SINKS.contains(methodName)) {
            call.getArguments().forEach(arg -> {
                if (isTainted(arg, method)) {
                    System.out.println("VULNERABILITY: Potential SQL Injection in " + method.getNameAsString() + " at line " + call.getBegin().get().line);
                }
            });
        }

        if (XSS_SINKS.contains(methodName)) {
            call.getArguments().forEach(arg -> {
                if (isTainted(arg, method)) {
                    System.out.println("VULNERABILITY: Potential XSS in " + method.getNameAsString() + " at line " + call.getBegin().get().line);
                }
            });
        }
    }

    private static boolean isTainted(Object expr, MethodDeclaration method) {
        String source = expr.toString();
        // Taint tracking: check if argument comes from method parameters (HTTP request inputs)
        return method.getParameters().stream().anyMatch(p -> p.getNameAsString().equals(source));
    }
}

